/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the SMS channel with:
 * - Phone number validation (E.164 format)
 * - Plain-text message formatting per notification type
 * - Pluggable transport (inject any send function — Twilio, SNS, etc.)
 * - In-memory fallback transport for development/testing
 *
 * NOTE: The user preferences model (src/models/user-preferences.ts) was built
 * assuming email-only channels. It needs to be updated to support per-channel
 * preferences (e.g., sms: { enabled, categories }) before SMS preferences
 * can be enforced. See the warning posted to Twining for details.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationType,
  NotificationResult,
} from '../models/notification.js';
import { isValidPhoneNumber } from '../validators/shared.validator.js';
import { Logger } from '../utils/logger.js';

/** Structure representing a formatted SMS ready for delivery. */
export interface FormattedSms {
  to: string;
  body: string;
}

/** Transport function signature — adapts to any SMS provider. */
export type SmsTransport = (sms: FormattedSms) => Promise<{ messageId: string }>;

/** Record of a sent SMS, stored in-memory for inspection. */
export interface SentSmsRecord {
  payload: NotificationPayload;
  formatted: FormattedSms;
  messageId: string;
  timestamp: Date;
}

/** Configuration for the SMS adapter. */
export interface SmsAdapterConfig {
  /** Optional custom transport. Falls back to in-memory transport if omitted. */
  transport?: SmsTransport;
}

/**
 * Format a notification payload as a plain-text SMS body.
 * SMS messages are length-limited, so templates are kept concise.
 */
function formatSmsBody(type: NotificationType, payload: NotificationPayload): string {
  switch (type) {
    case 'order_confirmation': {
      const orderId = payload.metadata?.orderId ? String(payload.metadata.orderId) : '';
      return orderId
        ? `Order ${orderId} confirmed. ${payload.body}`
        : `Order confirmed. ${payload.body}`;
    }
    case 'order_status_update': {
      const prev = payload.metadata?.previousStatus ? String(payload.metadata.previousStatus) : '';
      const next = payload.metadata?.newStatus ? String(payload.metadata.newStatus) : '';
      return prev && next
        ? `Order update: ${prev} → ${next}. ${payload.body}`
        : payload.body;
    }
    case 'welcome':
      return `Welcome to TaskFlow Pro! ${payload.body}`;
    case 'account_updated':
      return `Account updated: ${payload.body}`;
    default:
      return payload.body;
  }
}

/** Default in-memory transport for development and testing. */
function createInMemoryTransport(): SmsTransport {
  let counter = 0;
  return async () => ({ messageId: `sms-${Date.now()}-${++counter}` });
}

export class SmsNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'sms';
  private logger = new Logger('SmsAdapter');
  private sent: SentSmsRecord[] = [];
  private transport: SmsTransport;

  constructor(config?: Partial<SmsAdapterConfig>) {
    this.transport = config?.transport ?? createInMemoryTransport();
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!isValidPhoneNumber(payload.recipient)) {
      this.logger.warn(`Invalid phone number: ${payload.recipient}`);
      return {
        success: false,
        channel: this.channel,
        recipient: payload.recipient,
        error: `Invalid phone number: ${payload.recipient}`,
      };
    }

    const formatted: FormattedSms = {
      to: payload.recipient,
      body: formatSmsBody(payload.type, payload),
    };

    try {
      const { messageId } = await this.transport(formatted);

      this.logger.info(`SMS sent to ${payload.recipient} [${messageId}]`);
      this.sent.push({ payload, formatted, messageId, timestamp: new Date() });

      return {
        success: true,
        channel: this.channel,
        recipient: payload.recipient,
        messageId,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${errorMessage}`);

      return {
        success: false,
        channel: this.channel,
        recipient: payload.recipient,
        error: errorMessage,
      };
    }
  }

  /** Get all sent SMS records. */
  getSentMessages(): SentSmsRecord[] {
    return [...this.sent];
  }

  /** Clear sent SMS records. */
  clearSentMessages(): void {
    this.sent = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsNotificationAdapter,
  type SmsTransport,
  type FormattedSms,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    type: 'order_confirmation',
    recipient: '+14155551234',
    subject: 'Order Confirmation: ord-001',
    body: 'Your order has been placed. Items: Widget x2. Total: $25.00',
    metadata: { orderId: 'ord-001', userId: 'user-001' },
    ...overrides,
  };
}

describe('SmsNotificationAdapter', () => {
  let adapter: SmsNotificationAdapter;

  beforeEach(() => {
    adapter = new SmsNotificationAdapter();
  });

  describe('channel', () => {
    it('should report sms channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('configuration', () => {
    it('should accept custom transport', async () => {
      const transport: SmsTransport = async () => ({ messageId: 'custom-sms-123' });
      const custom = new SmsNotificationAdapter({ transport });
      const result = await custom.send(makePayload());
      expect(result.messageId).toBe('custom-sms-123');
    });
  });

  describe('phone number validation', () => {
    it('should reject empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should reject recipient without + prefix', async () => {
      const result = await adapter.send(makePayload({ recipient: '14155551234' }));
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should reject recipient with letters', async () => {
      const result = await adapter.send(makePayload({ recipient: '+1415abc1234' }));
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should reject too-short phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: '+12345' }));
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should reject phone number starting with +0', async () => {
      const result = await adapter.send(makePayload({ recipient: '+0123456789' }));
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should accept valid E.164 phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: '+14155551234' }));
      expect(result.success).toBe(true);
    });

    it('should accept international phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: '+442071234567' }));
      expect(result.success).toBe(true);
    });
  });

  describe('message formatting', () => {
    let captured: FormattedSms[];
    let captureAdapter: SmsNotificationAdapter;

    beforeEach(() => {
      captured = [];
      const transport: SmsTransport = async (sms) => {
        captured.push(sms);
        return { messageId: 'test-sms' };
      };
      captureAdapter = new SmsNotificationAdapter({ transport });
    });

    it('should format order_confirmation with order ID', async () => {
      await captureAdapter.send(makePayload());
      expect(captured).toHaveLength(1);
      expect(captured[0]!.body).toContain('Order ord-001 confirmed');
      expect(captured[0]!.to).toBe('+14155551234');
    });

    it('should format order_status_update with status transition', async () => {
      await captureAdapter.send(
        makePayload({
          type: 'order_status_update',
          body: 'Your order status has changed.',
          metadata: { orderId: 'ord-002', previousStatus: 'pending', newStatus: 'shipped' },
        }),
      );
      expect(captured[0]!.body).toContain('pending');
      expect(captured[0]!.body).toContain('shipped');
      expect(captured[0]!.body).toContain('→');
    });

    it('should format welcome message', async () => {
      await captureAdapter.send(
        makePayload({
          type: 'welcome',
          body: 'Welcome, Alice!',
        }),
      );
      expect(captured[0]!.body).toContain('Welcome to TaskFlow Pro!');
      expect(captured[0]!.body).toContain('Welcome, Alice!');
    });

    it('should format account_updated message', async () => {
      await captureAdapter.send(
        makePayload({
          type: 'account_updated',
          body: 'Email changed.',
        }),
      );
      expect(captured[0]!.body).toContain('Account updated:');
      expect(captured[0]!.body).toContain('Email changed.');
    });

    it('should fall back to body for unknown type', async () => {
      await captureAdapter.send(
        makePayload({
          type: 'order_confirmation',
          body: 'Test body',
          metadata: {},
        }),
      );
      expect(captured[0]!.body).toContain('Test body');
    });
  });

  describe('send success', () => {
    it('should return success result with messageId', async () => {
      const result = await adapter.send(makePayload());
      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');
      expect(result.recipient).toBe('+14155551234');
      expect(result.messageId).toBeDefined();
    });

    it('should track sent messages', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: '+442071234567' }));
      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(2);
      expect(sent[0]!.payload.recipient).toBe('+14155551234');
      expect(sent[1]!.payload.recipient).toBe('+442071234567');
    });

    it('should store formatted SMS in sent records', async () => {
      await adapter.send(makePayload());
      const sent = adapter.getSentMessages();
      expect(sent[0]!.formatted.to).toBe('+14155551234');
      expect(sent[0]!.formatted.body).toContain('Order ord-001 confirmed');
    });
  });

  describe('transport failure', () => {
    it('should return failure result when transport throws', async () => {
      const failing: SmsTransport = async () => {
        throw new Error('SMS gateway unavailable');
      };
      const failAdapter = new SmsNotificationAdapter({ transport: failing });
      const result = await failAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('SMS gateway unavailable');
      expect(result.channel).toBe('sms');
    });

    it('should not record failed sends in sent list', async () => {
      const failing: SmsTransport = async () => {
        throw new Error('timeout');
      };
      const failAdapter = new SmsNotificationAdapter({ transport: failing });
      await failAdapter.send(makePayload());
      expect(failAdapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('clearSentMessages', () => {
    it('should clear sent records', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);
      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });
});

